import socket
import struct
import json
import time
import random

# CoAP Constants
COAP_VERSION = 1
COAP_PORT = 5683

# CoAP Message Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Method Codes
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes
CREATED = (2, 1)
DELETED = (2, 2)
VALID = (2, 3)
CHANGED = (2, 4)
CONTENT = (2, 5)
BAD_REQUEST = (4, 0)
NOT_FOUND = (4, 4)
METHOD_NOT_ALLOWED = (4, 5)
INTERNAL_ERROR = (5, 0)

# CoAP Option Numbers
IF_MATCH = 1
URI_HOST = 3
URI_PORT = 7
URI_PATH = 11
CONTENT_FORMAT = 12
URI_QUERY = 15
ACCEPT = 17

# Content Format
TEXT_PLAIN = 0
APP_JSON = 50
APP_OCTET = 42


class CoapOption:
    def __init__(self, number, value=b''):
        self.number = number
        self.value = value


class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.type = CON
        self.token_length = 0
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @property
    def code(self):
        return (self.code_class, self.code_detail)

    @code.setter
    def code(self, value):
        if isinstance(value, tuple):
            self.code_class, self.code_detail = value
        else:
            self.code_class = (value >> 5) & 0x07
            self.code_detail = value & 0x1F

    def get_uri_path(self):
        parts = []
        for opt in self.options:
            if opt.number == URI_PATH:
                parts.append(opt.value.decode('utf-8'))
        return '/' + '/'.join(parts) if parts else '/'

    def encode(self):
        buf = bytearray()
        # Header
        byte0 = (self.version << 6) | (self.type << 4) | (self.token_length & 0x0F)
        byte1 = ((self.code_class & 0x07) << 5) | (self.code_detail & 0x1F)
        buf.append(byte0)
        buf.append(byte1)
        buf.append((self.message_id >> 8) & 0xFF)
        buf.append(self.message_id & 0xFF)

        # Token
        if self.token:
            buf.extend(self.token)

        # Options (sorted by number)
        self.options.sort(key=lambda o: o.number)
        prev_option_number = 0
        for opt in self.options:
            delta = opt.number - prev_option_number
            length = len(opt.value)

            # Encode delta
            if delta < 13:
                delta_nibble = delta
                delta_ext = b''
            elif delta < 269:
                delta_nibble = 13
                delta_ext = bytes([delta - 13])
            else:
                delta_nibble = 14
                delta_ext = struct.pack('!H', delta - 269)

            # Encode length
            if length < 13:
                length_nibble = length
                length_ext = b''
            elif length < 269:
                length_nibble = 13
                length_ext = bytes([length - 13])
            else:
                length_nibble = 14
                length_ext = struct.pack('!H', length - 269)

            buf.append((delta_nibble << 4) | length_nibble)
            buf.extend(delta_ext)
            buf.extend(length_ext)
            buf.extend(opt.value)

            prev_option_number = opt.number

        # Payload marker + payload
        if self.payload:
            buf.append(0xFF)
            if isinstance(self.payload, str):
                buf.extend(self.payload.encode('utf-8'))
            else:
                buf.extend(self.payload)

        return bytes(buf)

    @staticmethod
    def decode(data):
        msg = CoapMessage()
        if len(data) < 4:
            return None

        byte0 = data[0]
        msg.version = (byte0 >> 6) & 0x03
        msg.type = (byte0 >> 4) & 0x03
        msg.token_length = byte0 & 0x0F
        msg.code_class = (data[1] >> 5) & 0x07
        msg.code_detail = data[1] & 0x1F
        msg.message_id = (data[2] << 8) | data[3]

        idx = 4

        # Token
        if msg.token_length > 0 and idx + msg.token_length <= len(data):
            msg.token = data[idx:idx + msg.token_length]
            idx += msg.token_length

        # Options
        prev_option_number = 0
        while idx < len(data):
            if data[idx] == 0xFF:
                idx += 1
                break

            delta_nibble = (data[idx] >> 4) & 0x0F
            length_nibble = data[idx] & 0x0F
            idx += 1

            # Decode delta
            if delta_nibble < 13:
                delta = delta_nibble
            elif delta_nibble == 13:
                delta = data[idx] + 13
                idx += 1
            elif delta_nibble == 14:
                delta = struct.unpack('!H', data[idx:idx + 2])[0] + 269
                idx += 2
            else:
                break  # Reserved/payload marker

            # Decode length
            if length_nibble < 13:
                opt_length = length_nibble
            elif length_nibble == 13:
                opt_length = data[idx] + 13
                idx += 1
            elif length_nibble == 14:
                opt_length = struct.unpack('!H', data[idx:idx + 2])[0] + 269
                idx += 2
            else:
                break

            option_number = prev_option_number + delta
            opt_value = data[idx:idx + opt_length]
            idx += opt_length

            msg.options.append(CoapOption(option_number, opt_value))
            prev_option_number = option_number

        # Payload
        if idx < len(data):
            msg.payload = data[idx:]

        return msg


class DeviceState:
    """Holds the current state of all device resources."""
    def __init__(self):
        self.temperature = 22.5
        self.humidity = 55.0
        self.light_on = False
        self.light_brightness = 0
        self.last_temp_read = 0
        self.temp_read_interval = 2  # seconds

    def read_temperature(self):
        """Simulate reading temperature sensor (replace with real hardware call)."""
        now = time.time()
        if now - self.last_temp_read > self.temp_read_interval:
            # Simulate sensor noise
            self.temperature += (random.random() - 0.5) * 0.3
            self.temperature = round(self.temperature, 2)
            self.humidity += (random.random() - 0.5) * 0.5
            self.humidity = max(0, min(100, round(self.humidity, 1)))
            self.last_temp_read = now
        return self.temperature, self.humidity

    def set_light(self, on=None, brightness=None):
        """Control light actuator (replace with real GPIO call)."""
        if on is not None:
            self.light_on = bool(on)
        if brightness is not None:
            self.light_brightness = max(0, min(100, int(brightness)))
            if self.light_brightness > 0:
                self.light_on = True
            elif self.light_brightness == 0:
                self.light_on = False
        # In real implementation: set GPIO pin here
        # e.g., machine.Pin(2).value(1 if self.light_on else 0)
        print("[ACTUATOR] Light: on={}, brightness={}%".format(
            self.light_on, self.light_brightness))
        return self.light_on, self.light_brightness

    def get_light_state(self):
        return self.light_on, self.light_brightness


class ResourceHandler:
    """Base class for CoAP resource handlers."""
    def __init__(self, device_state):
        self.state = device_state

    def handle_get(self, request):
        raise NotImplementedError

    def handle_put(self, request):
        raise NotImplementedError


class TemperatureResource(ResourceHandler):
    """Handles /sensors/temp resource."""

    def handle_get(self, request):
        temp, humidity = self.state.read_temperature()
        payload = json.dumps({
            "temperature": temp,
            "humidity": humidity,
            "unit": "celsius",
            "ts": int(time.time())
        })
        return CONTENT, payload

    def handle_put(self, request):
        # Sensors are read-only
        return METHOD_NOT_ALLOWED, '{"error":"sensor is read-only"}'


class LightResource(ResourceHandler):
    """Handles /actuators/light resource."""

    def handle_get(self, request):
        on, brightness = self.state.get_light_state()
        payload = json.dumps({
            "on": on,
            "brightness": brightness,
            "ts": int(time.time())
        })
        return CONTENT, payload

    def handle_put(self, request):
        try:
            if request.payload:
                data = json.loads(request.payload.decode('utf-8'))
            else:
                return BAD_REQUEST, '{"error":"empty payload"}'

            on = data.get("on", None)
            brightness = data.get("brightness", None)

            if on is None and brightness is None:
                return BAD_REQUEST, '{"error":"provide on or brightness"}'

            new_on, new_brightness = self.state.set_light(on=on, brightness=brightness)
            payload = json.dumps({
                "on": new_on,
                "brightness": new_brightness,
                "ts": int(time.time())
            })
            return CHANGED, payload

        except (ValueError, KeyError) as e:
            return BAD_REQUEST, json.dumps({"error": str(e)})


class WellKnownCoreResource(ResourceHandler):
    """Handles /.well-known/core for CoAP resource discovery."""

    def __init__(self, device_state, resource_registry):
        super().__init__(device_state)
        self.resource_registry = resource_registry

    def handle_get(self, request):
        links = []
        for path, info in self.resource_registry.items():
            link = '<{}>'.format(path)
            if 'rt' in info:
                link += ';rt="{}"'.format(info['rt'])
            if 'ct' in info:
                link += ';ct={}'.format(info['ct'])
            links.append(link)
        payload = ','.join(links)
        return CONTENT, payload

    def handle_put(self, request):
        return METHOD_NOT_ALLOWED, ''


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host='0.0.0.0', port=COAP_PORT):
        self.host = host
        self.port = port
        self.sock = None
        self.resources = {}
        self.handlers = {}
        self.device_state = DeviceState()
        self.running = False
        self._msg_id_counter = random.getrandbits(16)

        # Register built-in resources
        self._register_default_resources()

    def _next_message_id(self):
        self._msg_id_counter = (self._msg_id_counter + 1) & 0xFFFF
        return self._msg_id_counter

    def _register_default_resources(self):
        # Temperature sensor
        self.add_resource(
            '/sensors/temp',
            TemperatureResource(self.device_state),
            rt='temperature',
            ct=APP_JSON
        )

        # Light actuator
        self.add_resource(
            '/actuators/light',
            LightResource(self.device_state),
            rt='light',
            ct=APP_JSON
        )

        # Resource discovery metadata (handler added separately)
        self.resources['/.well-known/core'] = {
            'rt': 'core.rd',
            'ct': 40  # application/link-format
        }

    def add_resource(self, path, handler, rt=None, ct=None):
        """Register a resource with its handler."""
        self.handlers[path] = handler
        info = {}
        if rt:
            info['rt'] = rt
        if ct is not None:
            info['ct'] = ct
        self.resources[path] = info

    def _build_response(self, request, code, payload=''):
        """Build a CoAP response message."""
        response = CoapMessage()

        # If request is Confirmable, respond with ACK; else NON
        if request.type == CON:
            response.type = ACK
        else:
            response.type = NON

        response.code = code
        response.message_id = request.message_id
        response.token = request.token
        response.token_length = request.token_length

        # Add content-format option if there's payload
        if payload:
            response.options.append(
                CoapOption(CONTENT_FORMAT, struct.pack('!B', APP_JSON))
            )
            if isinstance(payload, str):
                response.payload = payload.encode('utf-8')
            else:
                response.payload = payload

        return response

    def _handle_request(self, data, addr):
        """Parse incoming CoAP message and dispatch to the appropriate handler."""
        request = CoapMessage.decode(data)
        if request is None:
            print("[WARN] Failed to decode CoAP message from {}".format(addr))
            return None

        uri_path = request.get_uri_path()
        method = request.code_detail

        print("[REQ] {} {} from {}".format(
            {GET: 'GET', PUT: 'PUT', POST: 'POST', DELETE: 'DELETE'}.get(method, '?'),
            uri_path,
            addr
        ))

        # Resource discovery
        if uri_path == '/.well-known/core':
            discovery = WellKnownCoreResource(self.device_state, self.resources)
            code, payload = discovery.handle_get(request)
            return self._build_response(request, code, payload)

        # Lookup handler
        handler = self.handlers.get(uri_path)
        if handler is None:
            return self._build_response(request, NOT_FOUND,
                                        '{"error":"resource not found"}')

        # Dispatch by method
        if method == GET:
            code, payload = handler.handle_get(request)
        elif method == PUT:
            code, payload = handler.handle_put(request)
        else:
            code = METHOD_NOT_ALLOWED
            payload = '{"error":"method not allowed"}'

        return self._build_response(request, code, payload)

    def start(self):
        """Start the CoAP server."""
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))
        # Set a timeout so we can gracefully handle stop
        self.sock.settimeout(1.0)
        self.running = True

        print("=" * 50)
        print("CoAP Server started on {}:{}".format(self.host, self.port))
        print("Registered resources:")
        for path, info in self.resources.items():
            print("  {} -> {}".format(path, info))
        print("=" * 50)

        while self.running:
            try:
                data, addr = self.sock.recvfrom(1024)
                response = self._handle_request(data, addr)
                if response:
                    encoded = response.encode()
                    self.sock.sendto(encoded, addr)
                    print("[RSP] -> {} ({}.{:02d}) {} bytes".format(
                        addr,
                        response.code_class,
                        response.code_detail,
                        len(encoded)
                    ))
            except OSError:
                # Timeout - allows checking self.running
                continue
            except KeyboardInterrupt:
                print("\n[INFO] Shutting down...")
                break
            except Exception as e:
                print("[ERROR] {}".format(e))

        self.stop()

    def stop(self):
        """Stop the CoAP server."""
        self.running = False
        if self.sock:
            self.sock.close()
            self.sock = None
        print("[INFO] CoAP Server stopped.")


