# ---- CoAP Client Helper (for testing / mesh communication) ----

class CoapClient:
    """Minimal CoAP client for device-to-device mesh communication."""

    def __init__(self):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.settimeout(5.0)
        self._msg_id = random.getrandbits(16)

    def _next_id(self):
        self._msg_id = (self._msg_id + 1) & 0xFFFF
        return self._msg_id

    def get(self, host, port, path):
        """Send a CoAP GET request."""
        msg = CoapMessage()
        msg.type = CON
        msg.code = (0, GET)
        msg.message_id = self._next_id()
        msg.token = bytes([random.getrandbits(8)])
        msg.token_length = 1

        # Add URI path options
        for part in path.strip('/').split('/'):
            if part:
                msg.options.append(CoapOption(URI_PATH, part.encode('utf-8')))

        self.sock.sendto(msg.encode(), (host, port))
        try:
            data, addr = self.sock.recvfrom(1024)
            response = CoapMessage.decode(data)
            return response
        except OSError:
            print("[CLIENT] Timeout waiting for response")
            return None

    def put(self, host, port, path, payload):
        """Send a CoAP PUT request."""
        msg = CoapMessage()
        msg.type = CON
        msg.code = (0, PUT)
        msg.message_id = self._next_id()
        msg.token = bytes([random.getrandbits(8)])
        msg.token_length = 1

        for part in path.strip('/').split('/'):
            if part:
                msg.options.append(CoapOption(URI_PATH, part.encode('utf-8')))

        msg.options.append(
            CoapOption(CONTENT_FORMAT, struct.pack('!B', APP_JSON))
        )

        if isinstance(payload, str):
            msg.payload = payload.encode('utf-8')
        elif isinstance(payload, dict):
            msg.payload = json.dumps(payload).encode('utf-8')
        else:
            msg.payload = payload

        self.sock.sendto(msg.encode(), (host, port))
        try:
            data, addr = self.sock.recvfrom(1024)
            response = CoapMessage.decode(data)
            return response
        except OSError:
            print("[CLIENT] Timeout waiting for response")
            return None

    def close(self):
        self.sock.close()


